import { PrecisionClock } from '@psyforge/timing';
import { performance } from 'perf_hooks';

export interface TimingMetrics {
  fps: number;
  frameVariance: number;
  droppedFrames: number;
  heapUsage: number;
  refreshRate: number;
  browserInfo: {
    userAgent: string;
    platform: string;
    hardwareConcurrency: number;
  };
  displayInfo: {
    width: number;
    height: number;
    colorDepth: number;
    refreshRate: number;
  };
  webGLInfo?: {
    version: string;
    vendor: string;
    renderer: string;
    extensions: string[];
  };
}

export interface ValidationReport {
  timestamp: number;
  duration: number;
  metrics: TimingMetrics;
  capabilities: {
    webGL2: boolean;
    webGL1: boolean;
    requestVideoFrameCallback: boolean;
    highResolutionTime: boolean;
    webAudioAPI: boolean;
  };
  timingPrecision: {
    measured: number;
    target: number;
    meetsTarget: boolean;
  };
  recommendations: string[];
  warnings: string[];
}

export class HardwareTimingValidator {
  private clock: PrecisionClock;
  private frameTimestamps: number[] = [];
  private droppedFrames = 0;
  private animationId?: number;
  private startTime?: number;
  private canvas?: HTMLCanvasElement;
  private gl?: WebGLRenderingContext | WebGL2RenderingContext | null;

  constructor() {
    this.clock = new PrecisionClock();
  }

  async validate(durationMs = 5000): Promise<ValidationReport> {
    const startTime = performance.now();
    this.startTime = startTime;
    this.frameTimestamps = [];
    this.droppedFrames = 0;

    // Create test canvas
    this.canvas = document.createElement('canvas');
    this.canvas.width = 800;
    this.canvas.height = 600;
    document.body.appendChild(this.canvas);

    // Detect capabilities
    const capabilities = this.detectCapabilities();

    // Initialize WebGL context
    this.initializeWebGL();

    // Run timing test
    await this.runTimingTest(durationMs);

    // Calculate metrics
    const metrics = this.calculateMetrics();

    // Generate report
    const report = this.generateReport(
      startTime,
      performance.now() - startTime,
      metrics,
      capabilities
    );

    // Cleanup
    this.cleanup();

    return report;
  }

  private detectCapabilities() {
    return {
      webGL2: this.checkWebGL2Support(),
      webGL1: this.checkWebGL1Support(),
      requestVideoFrameCallback: 'requestVideoFrameCallback' in HTMLVideoElement.prototype,
      highResolutionTime: typeof performance.now === 'function',
      webAudioAPI: typeof AudioContext !== 'undefined' || typeof (window as any).webkitAudioContext !== 'undefined'
    };
  }

  private checkWebGL2Support(): boolean {
    const canvas = document.createElement('canvas');
    const gl = canvas.getContext('webgl2');
    return gl !== null;
  }

  private checkWebGL1Support(): boolean {
    const canvas = document.createElement('canvas');
    const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
    return gl !== null;
  }

  private initializeWebGL() {
    if (!this.canvas) return;

    // Try WebGL2 first
    this.gl = this.canvas.getContext('webgl2');
    if (!this.gl) {
      // Fall back to WebGL1
      this.gl = this.canvas.getContext('webgl') || 
                this.canvas.getContext('experimental-webgl');
    }
  }

  private async runTimingTest(durationMs: number): Promise<void> {
    return new Promise((resolve) => {
      let lastTimestamp = 0;
      const targetFrameTime = 1000 / 60; // 60fps target

      const frameCallback = (timestamp: number) => {
        if (!this.startTime) return;

        this.frameTimestamps.push(timestamp);

        // Check for dropped frames
        if (lastTimestamp > 0) {
          const delta = timestamp - lastTimestamp;
          if (delta > targetFrameTime * 1.5) {
            this.droppedFrames++;
          }
        }
        lastTimestamp = timestamp;

        // Continue test
        if (timestamp - this.startTime < durationMs) {
          this.animationId = requestAnimationFrame(frameCallback);
        } else {
          resolve();
        }
      };

      this.animationId = requestAnimationFrame(frameCallback);
    });
  }

  private calculateMetrics(): TimingMetrics {
    const fps = this.calculateFPS();
    const frameVariance = this.calculateFrameVariance();
    const heapUsage = this.getHeapUsage();
    const refreshRate = this.detectRefreshRate();

    return {
      fps,
      frameVariance,
      droppedFrames: this.droppedFrames,
      heapUsage,
      refreshRate,
      browserInfo: this.getBrowserInfo(),
      displayInfo: this.getDisplayInfo(refreshRate),
      webGLInfo: this.getWebGLInfo()
    };
  }

  private calculateFPS(): number {
    if (this.frameTimestamps.length < 2) return 0;

    const duration = this.frameTimestamps[this.frameTimestamps.length - 1] - this.frameTimestamps[0];
    return (this.frameTimestamps.length - 1) / (duration / 1000);
  }

  private calculateFrameVariance(): number {
    if (this.frameTimestamps.length < 3) return 0;

    const deltas: number[] = [];
    for (let i = 1; i < this.frameTimestamps.length; i++) {
      deltas.push(this.frameTimestamps[i] - this.frameTimestamps[i - 1]);
    }

    const mean = deltas.reduce((sum, delta) => sum + delta, 0) / deltas.length;
    const variance = deltas.reduce((sum, delta) => sum + Math.pow(delta - mean, 2), 0) / deltas.length;

    return Math.sqrt(variance);
  }

  private getHeapUsage(): number {
    if ('memory' in performance && (performance as any).memory) {
      return (performance as any).memory.usedJSHeapSize / 1024 / 1024; // MB
    }
    return 0;
  }

  private detectRefreshRate(): number {
    // Estimate refresh rate from frame timestamps
    if (this.frameTimestamps.length < 10) return 60;

    const deltas: number[] = [];
    for (let i = 1; i < Math.min(100, this.frameTimestamps.length); i++) {
      deltas.push(this.frameTimestamps[i] - this.frameTimestamps[i - 1]);
    }

    const avgDelta = deltas.reduce((sum, d) => sum + d, 0) / deltas.length;
    const estimatedFPS = 1000 / avgDelta;

    // Round to common refresh rates
    const commonRates = [60, 75, 90, 120, 144, 240];
    return commonRates.reduce((closest, rate) => 
      Math.abs(rate - estimatedFPS) < Math.abs(closest - estimatedFPS) ? rate : closest
    );
  }

  private getBrowserInfo() {
    return {
      userAgent: navigator.userAgent,
      platform: navigator.platform,
      hardwareConcurrency: navigator.hardwareConcurrency || 1
    };
  }

  private getDisplayInfo(refreshRate: number) {
    return {
      width: window.screen.width,
      height: window.screen.height,
      colorDepth: window.screen.colorDepth,
      refreshRate
    };
  }

  private getWebGLInfo() {
    if (!this.gl) return undefined;

    const debugInfo = this.gl.getExtension('WEBGL_debug_renderer_info');

    return {
      version: this.gl.getParameter(this.gl.VERSION),
      vendor: debugInfo ? this.gl.getParameter(debugInfo.UNMASKED_VENDOR_WEBGL) : 'Unknown',
      renderer: debugInfo ? this.gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) : 'Unknown',
      extensions: this.gl.getSupportedExtensions() || []
    };
  }

  private generateReport(
    startTime: number,
    duration: number,
    metrics: TimingMetrics,
    capabilities: ReturnType<typeof this.detectCapabilities>
  ): ValidationReport {
    const timingPrecision = this.measureTimingPrecision();
    const recommendations = this.generateRecommendations(metrics, capabilities, timingPrecision);
    const warnings = this.generateWarnings(metrics, capabilities);

    return {
      timestamp: startTime,
      duration,
      metrics,
      capabilities,
      timingPrecision,
      recommendations,
      warnings
    };
  }

  private measureTimingPrecision(): { measured: number; target: number; meetsTarget: boolean } {
    // Measure actual timing precision
    const samples: number[] = [];
    for (let i = 0; i < 100; i++) {
      samples.push(performance.now());
    }

    // Calculate precision from consecutive samples
    const deltas: number[] = [];
    for (let i = 1; i < samples.length; i++) {
      const delta = samples[i] - samples[i - 1];
      if (delta > 0) deltas.push(delta);
    }

    const measured = deltas.length > 0 ? Math.min(...deltas) : 1;
    const target = 2; // 2ms target

    return {
      measured,
      target,
      meetsTarget: measured <= target
    };
  }

  private generateRecommendations(
    metrics: TimingMetrics,
    capabilities: ReturnType<typeof this.detectCapabilities>,
    timingPrecision: { measured: number; target: number; meetsTarget: boolean }
  ): string[] {
    const recommendations: string[] = [];

    if (!timingPrecision.meetsTarget) {
      recommendations.push(`Timing precision (${timingPrecision.measured.toFixed(2)}ms) exceeds target (${timingPrecision.target}ms). Consider using a dedicated timing device.`);
    }

    if (metrics.fps < 55) {
      recommendations.push('Frame rate below 60fps. Check system performance and close unnecessary applications.');
    }

    if (metrics.frameVariance > 5) {
      recommendations.push('High frame timing variance detected. This may impact stimulus presentation accuracy.');
    }

    if (metrics.droppedFrames > 0) {
      recommendations.push(`${metrics.droppedFrames} dropped frames detected. Reduce system load for optimal performance.`);
    }

    if (!capabilities.webGL2) {
      recommendations.push('WebGL2 not supported. Some advanced rendering features may be unavailable.');
    }

    if (!capabilities.requestVideoFrameCallback) {
      recommendations.push('requestVideoFrameCallback not supported. Video timing precision may be limited.');
    }

    if (metrics.refreshRate !== 60 && metrics.refreshRate !== 120 && metrics.refreshRate !== 144) {
      recommendations.push(`Non-standard refresh rate (${metrics.refreshRate}Hz) detected. Timing calculations may need adjustment.`);
    }

    return recommendations;
  }

  private generateWarnings(
    metrics: TimingMetrics,
    capabilities: ReturnType<typeof this.detectCapabilities>
  ): string[] {
    const warnings: string[] = [];

    if (!capabilities.highResolutionTime) {
      warnings.push('High-resolution timing not available. Timing precision will be severely limited.');
    }

    if (!capabilities.webAudioAPI) {
      warnings.push('Web Audio API not available. Audio timing synchronization will be limited.');
    }

    if (metrics.heapUsage > 1000) {
      warnings.push(`High memory usage detected (${metrics.heapUsage.toFixed(0)}MB). This may impact performance.`);
    }

    if (metrics.browserInfo.hardwareConcurrency < 4) {
      warnings.push('Low CPU core count detected. Complex experiments may experience performance issues.');
    }

    return warnings;
  }

  private cleanup() {
    if (this.animationId) {
      cancelAnimationFrame(this.animationId);
    }

    if (this.canvas && this.canvas.parentNode) {
      this.canvas.parentNode.removeChild(this.canvas);
    }

    this.gl = null;
    this.canvas = undefined;
    this.frameTimestamps = [];
  }

  async exportReport(report: ValidationReport): Promise<string> {
    const exportData = {
      ...report,
      exportedAt: new Date().toISOString(),
      version: '1.0.0'
    };

    return JSON.stringify(exportData, null, 2);
  }

  generateCompatibilityMatrix(reports: ValidationReport[]): Record<string, any> {
    const matrix: Record<string, any> = {
      browsers: {},
      platforms: {},
      refreshRates: {},
      capabilities: {
        webGL2: { supported: 0, total: 0 },
        webGL1: { supported: 0, total: 0 },
        requestVideoFrameCallback: { supported: 0, total: 0 },
        highResolutionTime: { supported: 0, total: 0 },
        webAudioAPI: { supported: 0, total: 0 }
      }
    };

    for (const report of reports) {
      // Track browser usage
      const browser = this.parseBrowser(report.metrics.browserInfo.userAgent);
      matrix.browsers[browser] = (matrix.browsers[browser] || 0) + 1;

      // Track platform
      const platform = report.metrics.browserInfo.platform;
      matrix.platforms[platform] = (matrix.platforms[platform] || 0) + 1;

      // Track refresh rates
      const refreshRate = report.metrics.refreshRate;
      matrix.refreshRates[refreshRate] = (matrix.refreshRates[refreshRate] || 0) + 1;

      // Track capabilities
      for (const [key, value] of Object.entries(report.capabilities)) {
        if (key in matrix.capabilities) {
          matrix.capabilities[key].total++;
          if (value) matrix.capabilities[key].supported++;
        }
      }
    }

    return matrix;
  }

  private parseBrowser(userAgent: string): string {
    if (userAgent.includes('Chrome')) return 'Chrome';
    if (userAgent.includes('Firefox')) return 'Firefox';
    if (userAgent.includes('Safari') && !userAgent.includes('Chrome')) return 'Safari';
    if (userAgent.includes('Edge')) return 'Edge';
    return 'Other';
  }
}

