// 🚀 ENHANCED FORGESCRIPT FLUENT API & COMPILER - Primary API (Sprint 2)
export { 
  FluentExperimentBuilder,
  experiment,
  conditions,
  trial,
  type PowerAnalysisOptions,
  type PowerAnalysisResult,
  type ConditionBuilder,
  type TrialBuilder as FluentTrialBuilder
} from './api/FluentExperimentBuilder.js';

// ForgeScript Compiler & FZB Binary Format
export {
  ForgeScriptCompiler,
  compileExperiment,
  decompileExperiment,
  type CompilerOptions,
  type CompilerResult,
  type CompilerError,
  type CompilerWarning,
  type CompilerMetadata,
  type FZBHeader
} from './compiler/ForgeScriptCompiler.js';

// 🚀 REVOLUTIONARY COMPONENT SYSTEM - Alternative API
export { 
  ComponentForge,
  createComponentForge,
  ComponentExperiments,
  type ComponentForgeOptions
} from './ComponentForge.js';

// Modern Component System (Revolutionary Stimulus Architecture)
export * from './components/index.js';

// 🎯 ALTERNATIVE APIS (For specific use cases)
// Note: FluentExperimentBuilder above is the recommended primary API for Sprint 2

// Advanced Component Builder (For custom component development)
export { 
  ForgeBuilder, 
  Trial, 
  createForge, 
  createForgeWithDefaults,
  Experiments, 
  type ForgeBuilderOptions, 
  type TrialBuilder as ForgeTrialBuilder 
} from './ForgeBuilder.js';

// Serialization and validation
export { 
  Serializer, 
  type SerializationOptions, 
  type SerializedExperiment 
} from './serialization/Serializer.js';
export { 
  Validator, 
  type ValidationResult, 
  type ValidationError, 
  type ValidationWarning, 
  type ValidationOptions 
} from './serialization/Validator.js';

// Import necessary classes for helper functions
import { Experiment, type ExperimentOptions } from './core/Experiment.js';
import { Timeline } from './core/Timeline.js';
import { TextStimulus } from './stimuli/Text.js';
import { ImageStimulus } from './stimuli/Image.js';
import { AudioStimulus } from './stimuli/Audio.js';
import { VideoStimulus } from './stimuli/Video.js';
import { KeyboardResponse } from './responses/KeyboardResponse.js';
import { MouseResponse } from './responses/MouseResponse.js';
import { TouchResponse } from './responses/TouchResponse.js';
import { WaitEvent } from './events/Wait.js';
import { Runtime, type RuntimeConfiguration } from './core/Runtime.js';
import { Serializer, type SerializationOptions as SerializerOptions } from './serialization/Serializer.js';
import { Validator, type ValidationOptions as ValidatorOptions } from './serialization/Validator.js';

// Export PixiJS stimulus types
export * from './stimuli/index.js';

// Export data management and BIDS schema
export * from './data/index.js';

// Helper functions and utilities
export const ForgeScript = {
  // Factory functions for common patterns
  createExperiment: (title: string, options?: ExperimentOptions) => {
    return new Experiment(crypto.randomUUID(), options).title(title);
  },

  createTimeline: (id: string) => {
    return new Timeline(id);
  },

  createTextStimulus: (text: string, duration?: number) => {
    const stimulus = new TextStimulus(crypto.randomUUID(), text);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createImageStimulus: (src: string, duration?: number) => {
    const stimulus = new ImageStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createAudioStimulus: (src: string, duration?: number) => {
    const stimulus = new AudioStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createVideoStimulus: (src: string, duration?: number) => {
    const stimulus = new VideoStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createKeyboardResponse: (keys?: string[], timeout?: number) => {
    const response = new KeyboardResponse(crypto.randomUUID());
    if (keys) response.keys(keys);
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createMouseResponse: (timeout?: number) => {
    const response = new MouseResponse(crypto.randomUUID());
