import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { EnhancedStimulusRenderer } from '../EnhancedStimulusRenderer';
import * as PIXI from 'pixi.js';

// Mock PIXI
vi.mock('pixi.js', () => ({
  Application: vi.fn().mockImplementation(() => ({
    init: vi.fn().mockResolvedValue(undefined),
    stage: {
      sortableChildren: true,
      eventMode: 'static',
      removeChildren: vi.fn()
    },
    canvas: {
      id: '',
      style: {},
      width: 800,
      height: 600
    },
    renderer: {
      resize: vi.fn(),
      background: { color: 0 },
      extract: {
        base64: vi.fn().mockResolvedValue('data:image/png;base64,test')
      }
    },
    ticker: { FPS: 60 },
    render: vi.fn(),
    destroy: vi.fn()
  })),
  utils: {
    TextureCache: {}
  }
}));

describe('EnhancedStimulusRenderer', () => {
  let renderer: EnhancedStimulusRenderer;
  let mockCanvas: any;
  let mockContext2D: any;
  let mockWebGL2Context: any;
  let mockWebGL1Context: any;

  beforeEach(() => {
    // Reset singleton
    (EnhancedStimulusRenderer as any).instance = undefined;

    // Mock canvas and contexts
    mockContext2D = {
      fillStyle: '',
      fillRect: vi.fn(),
      clearRect: vi.fn(),
      font: '',
      textAlign: '',
      textBaseline: '',
      fillText: vi.fn(),
      drawImage: vi.fn(),
      beginPath: vi.fn(),
      arc: vi.fn(),
      fill: vi.fn()
    };

    mockWebGL2Context = {
      getParameter: vi.fn((param: number) => {
        switch (param) {
          case 3379: return 16384; // MAX_TEXTURE_SIZE
          case 34024: return 16384; // MAX_RENDERBUFFER_SIZE
          default: return 0;
        }
      }),
      getSupportedExtensions: vi.fn(() => ['EXT_texture_filter_anisotropic'])
    };

    mockWebGL1Context = {
      getParameter: vi.fn((param: number) => {
        switch (param) {
          case 3379: return 8192; // MAX_TEXTURE_SIZE
          case 34024: return 8192; // MAX_RENDERBUFFER_SIZE
          default: return 0;
        }
      }),
      getSupportedExtensions: vi.fn(() => ['OES_texture_float'])
    };

    mockCanvas = {
      getContext: vi.fn((type: string) => {
        switch (type) {
          case 'webgl2': return mockWebGL2Context;
          case 'webgl':
          case 'experimental-webgl': return mockWebGL1Context;
          case '2d': return mockContext2D;
          default: return null;
        }
      }),
      width: 800,
      height: 600,
      style: {},
      toDataURL: vi.fn(() => 'data:image/png;base64,fallback')
    };

    // Mock document
    global.document = {
      createElement: vi.fn(() => mockCanvas),
      body: {
        appendChild: vi.fn()
      }
    } as any;

    // Mock window
    global.window = {
      innerWidth: 1920,
      innerHeight: 1080,
      devicePixelRatio: 2,
      addEventListener: vi.fn(),
      removeEventListener: vi.fn()
    } as any;

    renderer = EnhancedStimulusRenderer.getInstance();
  });

  afterEach(() => {
    renderer.destroy();
    vi.clearAllMocks();
  });

  describe('Capabilities Detection', () => {
    it('should detect WebGL2 support', () => {
      const capabilities = renderer.getCapabilities();

      expect(capabilities.webGL2).toBe(true);
      expect(capabilities.webGL1).toBe(true);
      expect(capabilities.canvas2D).toBe(true);
      expect(capabilities.renderer).toBe('webgl2');
      expect(capabilities.maxTextureSize).toBe(16384);
    });

    it('should fall back to WebGL1 when WebGL2 is not available', () => {
      mockCanvas.getContext.mockImplementation((type: string) => {
        if (type === 'webgl2') return null;
        if (type === 'webgl' || type === 'experimental-webgl') return mockWebGL1Context;
        if (type === '2d') return mockContext2D;
        return null;
      });

      const newRenderer = new (EnhancedStimulusRenderer as any)();
      const capabilities = newRenderer.getCapabilities();

      expect(capabilities.webGL2).toBe(false);
      expect(capabilities.webGL1).toBe(true);
      expect(capabilities.renderer).toBe('webgl');
      expect(capabilities.maxTextureSize).toBe(8192);
    });

    it('should fall back to Canvas2D when no WebGL is available', () => {
      mockCanvas.getContext.mockImplementation((type: string) => {
        if (type === '2d') return mockContext2D;
        return null;
      });

      const newRenderer = new (EnhancedStimulusRenderer as any)();
      const capabilities = newRenderer.getCapabilities();

      expect(capabilities.webGL2).toBe(false);
      expect(capabilities.webGL1).toBe(false);
      expect(capabilities.canvas2D).toBe(true);
      expect(capabilities.renderer).toBe('canvas');
    });
  });

  describe('Initialization', () => {
    it('should initialize with PIXI when WebGL is available', async () => {
      await renderer.initialize();

      expect(PIXI.Application).toHaveBeenCalled();
      expect(document.body.appendChild).toHaveBeenCalled();
      expect(renderer.isUsingFallback()).toBe(false);
    });

    it('should use Canvas2D fallback when WebGL fails', async () => {
      // Mock PIXI initialization failure
      const mockApp = new (PIXI.Application as any)();
      mockApp.init.mockRejectedValue(new Error('WebGL not supported'));

      await renderer.initialize({ enableFallback: true });

      expect(renderer.isUsingFallback()).toBe(true);
      expect(document.body.appendChild).toHaveBeenCalledWith(mockCanvas);
    });

    it('should throw error when no renderer is available', async () => {
      mockCanvas.getContext.mockReturnValue(null);

      await expect(renderer.initialize()).rejects.toThrow('No suitable renderer available');
    });

    it('should respect preferWebGL2 option', async () => {
      await renderer.initialize({ preferWebGL2: false });

      const app = renderer.getApp();
      expect(app).toBeDefined();
    });

    it('should set background color correctly', async () => {
      await renderer.initialize({ backgroundColor: '#FF0000' });

      const app = renderer.getApp();
      expect(app).toBeDefined();
    });
  });

  describe('Fallback Rendering', () => {
    beforeEach(async () => {
      // Force Canvas2D fallback
      mockCanvas.getContext.mockImplementation((type: string) => {
        if (type === '2d') return mockContext2D;
        return null;
      });

      await renderer.initialize({ enableFallback: true });
    });

    it('should render text stimulus in fallback mode', async () => {
      const mockStimulus = {
        id: 'test-text',
        constructor: { name: 'TextStimulusPixi' },
        text: 'Hello World',
        fontSize: 24,
        fontFamily: 'Arial',
