/**
 * WebGL2 Feature Detection and Fallback Demo
 * 
 * This example demonstrates how the enhanced renderer automatically
 * detects WebGL capabilities and falls back to Canvas2D when needed.
 */

import { 
  EnhancedStimulusRenderer,
  experiment,
  TextStimulusPixi,
  ShapeStimulusPixi,
  ImageStimulusPixi
} from '@psyforge/forgescript';

async function runFallbackDemo() {
  console.log('🎮 Starting WebGL Fallback Demo...\n');

  // Get renderer instance
  const renderer = EnhancedStimulusRenderer.getInstance();

  // Check capabilities before initialization
  const capabilities = renderer.getCapabilities();

  console.log('📊 System Capabilities:');
  console.log(`   WebGL2: ${capabilities.webGL2 ? '✅' : '❌'}`);
  console.log(`   WebGL1: ${capabilities.webGL1 ? '✅' : '❌'}`);
  console.log(`   Canvas2D: ${capabilities.canvas2D ? '✅' : '❌'}`);
  console.log(`   Renderer: ${capabilities.renderer}`);
  console.log(`   Max Texture Size: ${capabilities.maxTextureSize}`);
  console.log('');

  // Test different initialization modes
  await testWebGL2Mode(renderer);
  await testWebGL1Mode(renderer);
  await testCanvas2DFallback(renderer);

  // Run a simple experiment with automatic detection
  await runExperimentWithFallback();
}

async function testWebGL2Mode(renderer: EnhancedStimulusRenderer) {
  console.log('🔷 Testing WebGL2 Mode...');

  try {
    await renderer.initialize({
      preferWebGL2: true,
      enableFallback: false,
      backgroundColor: '#1a1a1a'
    });

    if (!renderer.isUsingFallback()) {
      console.log('✅ Successfully initialized with WebGL2');

      // Test stimulus rendering
      const textStimulus = new TextStimulusPixi('test-text', 'WebGL2 Rendering Test');
      await textStimulus.initialize({} as any);

      console.log('   Rendered text stimulus successfully');
    }
  } catch (error) {
    console.log('❌ WebGL2 initialization failed:', error);
  }

  renderer.destroy();
}

async function testWebGL1Mode(renderer: EnhancedStimulusRenderer) {
  console.log('\n🔶 Testing WebGL1 Mode...');

  try {
    await renderer.initialize({
      preferWebGL2: false,
      enableFallback: false,
      backgroundColor: '#2a2a2a'
    });

    if (!renderer.isUsingFallback()) {
      console.log('✅ Successfully initialized with WebGL1');

      // Test performance
      const fps = renderer.getFPS();
      console.log(`   Current FPS: ${fps}`);
    }
  } catch (error) {
    console.log('❌ WebGL1 initialization failed:', error);
  }

  renderer.destroy();
}

async function testCanvas2DFallback(renderer: EnhancedStimulusRenderer) {
  console.log('\n📐 Testing Canvas2D Fallback...');

  // Force fallback by simulating WebGL failure
  const originalGetContext = HTMLCanvasElement.prototype.getContext;
  HTMLCanvasElement.prototype.getContext = function(contextType: string) {
    if (contextType.includes('webgl')) {
      return null;
    }
    return originalGetContext.call(this, contextType as any);
  };

  try {
    await renderer.initialize({
      enableFallback: true,
      backgroundColor: '#3a3a3a'
    });

    if (renderer.isUsingFallback()) {
      console.log('✅ Successfully fell back to Canvas2D');
      console.log('⚠️  Limited features in fallback mode:');
      console.log('   - No WebGL effects');
      console.log('   - Basic shape rendering only');
      console.log('   - Reduced performance');
    }
  } catch (error) {
    console.log('❌ Canvas2D fallback failed:', error);
  }

  // Restore original getContext
  HTMLCanvasElement.prototype.getContext = originalGetContext;
  renderer.destroy();
}

async function runExperimentWithFallback() {
  console.log('\n🧪 Running Experiment with Automatic Fallback...\n');

  // Create a simple experiment
  const exp = experiment('WebGL Fallback Test')
    .author('Psycho-Forge Team')
    .description('Tests rendering with automatic WebGL fallback')

    .trial('compatibility_check')
      .stimulus(async (trial) => {
        const renderer = EnhancedStimulusRenderer.getInstance();
        const capabilities = renderer.getCapabilities();

        const message = capabilities.webGL2 
          ? 'Running with WebGL2 acceleration!' 
          : capabilities.webGL1
          ? 'Running with WebGL1 support'
          : 'Running in Canvas2D fallback mode';

        return new TextStimulusPixi('compat-text', message)
          .fontSize(32)
          .color('#00ff00')
          .duration(2000);
      })
      .build()

    .trial('performance_test')
      .stimulus(() => {
        // Create multiple shapes to test performance
        const shapes = [];

        for (let i = 0; i < 5; i++) {
          const shape = ShapeStimulusPixi.circle(50)
            .fillColor(0xff0000 + i * 0x002200)
            .position(100 + i * 150, 300);
          shapes.push(shape);
        }

        return shapes;
      })
      .response('keyboard', ['space'])
      .instruction('Press SPACE to continue')
      .build()

    .trial('feature_test')
      .stimulus(() => {
        const renderer = EnhancedStimulusRenderer.getInstance();

        if (renderer.isUsingFallback()) {
          return new TextStimulusPixi('fallback-warning', 
            'Note: Some visual effects are limited in Canvas2D mode')
            .fontSize(24)
            .color('#ffff00');
        } else {
          return new TextStimulusPixi('full-features', 
            'Full WebGL features available!')
            .fontSize(24)
            .color('#00ff00');
        }
      })
      .duration(3000)
      .build()

    .build();

  console.log('📋 Experiment Configuration:');
  console.log(`   Title: ${exp.metadata.title}`);
  console.log(`   Trials: ${exp.getTimeline().length}`);
  console.log('');

  // Check final renderer state
  const renderer = EnhancedStimulusRenderer.getInstance();
  await renderer.initialize({
    enableFallback: true,
    powerPreference: 'high-performance'
  });

  console.log('🎯 Final Renderer Status:');
  console.log(`   Using Fallback: ${renderer.isUsingFallback()}`);
  console.log(`   FPS: ${renderer.getFPS()}`);

  const memUsage = renderer.getMemoryUsage();
  console.log(`   Texture Memory: ${(memUsage.textureMemory / 1024 / 1024).toFixed(2)} MB`);

  const perfMetrics = renderer.getPerformanceMetrics();
  if (perfMetrics?.current) {
    console.log(`   Frame Time: ${perfMetrics.current.frameTime.toFixed(2)} ms`);
  }

  // Cleanup
  renderer.destroy();
}

// Performance comparison function
async function compareRendererPerformance() {
  console.log('\n📊 Renderer Performance Comparison:\n');

  const results = {
    webgl2: { fps: 0, frameTime: 0 },
    webgl1: { fps: 0, frameTime: 0 },
    canvas2d: { fps: 0, frameTime: 0 }
  };

  // Test WebGL2 performance
  const renderer = EnhancedStimulusRenderer.getInstance();

  // Note: In a real scenario, you would run actual rendering tests
  // and measure performance over time

  console.log('Performance Comparison Results:');
  console.log('| Renderer | Expected FPS | Frame Time | Features |');
  console.log('|----------|--------------|------------|----------|');
  console.log('| WebGL2   | 144+         | <7ms       | Full     |');
  console.log('| WebGL1   | 60-120       | 8-16ms     | Most     |');
  console.log('| Canvas2D | 30-60        | 16-33ms    | Basic    |');
}

// Run the demo
if (typeof window !== 'undefined') {
  window.addEventListener('DOMContentLoaded', async () => {
    try {
      await runFallbackDemo();
      await compareRendererPerformance();
    } catch (error) {
      console.error('Demo failed:', error);
    }
  });
} else {
