// Original stimulus types (DOM-based)
export { TextStimulus, type TextStimulusOptions } from './Text.js';
export { ImageStimulus, type ImageStimulusOptions } from './Image.js';
export { AudioStimulus, type AudioStimulusOptions } from './Audio.js';
export { VideoStimulus, type VideoStimulusOptions } from './Video.js';

// PixiJS-based stimulus types
export { BaseStimulus, type StimulusOptions } from './BaseStimulus.js';
export { TextStimulusPixi, type TextStimulusPixiOptions } from './TextStimulusPixi.js';
export { ImageStimulusPixi, type ImageStimulusPixiOptions } from './ImageStimulusPixi.js';
export { 
  ShapeStimulusPixi, 
  type ShapeStimulusPixiOptions,
  type ShapeType,
  rectangle,
  square,
  circle,
  ellipse,
  polygon,
  star
} from './ShapeStimulusPixi.js';

// Stimulus renderer
export { StimulusRenderer, type RendererOptions } from './StimulusRenderer.js';

// Helper function to create stimuli
export function createStimulus(type: string, id: string, ...args: any[]): BaseStimulus {
  switch (type) {
    case 'text':
      return new TextStimulusPixi(id, args[0], args[1]);
    case 'image':
      return new ImageStimulusPixi(id, args[0], args[1]);
    case 'rectangle':
      return rectangle(id, args[0], args[1]);
    case 'square':
      return square(id, args[0]);
    case 'circle':
      return circle(id, args[0]);
    case 'ellipse':
      return ellipse(id, args[0], args[1]);
    case 'polygon':
      return polygon(id, args[0], args[1]);
    case 'star':
      return star(id, args[0], args[1], args[2]);
    default:
      throw new Error(`Unknown stimulus type: ${type}`);
  }
}

